content.beginner:
Props are like function arguments for your components. You pass data into a component using props, and the component can display it:

```jsx
function Card({ title, description }) {
  return (
    <div>
      <h2>{title}</h2>
      <p>{description}</p>
    </div>
  );
}

<Card title="Hello" description="This is a card" />

State is data that can change over time. Use the `useState` hook to add state to a component:

```jsx
import { useState } from 'react';

function Counter() {
  const [count, setCount] = useState(0);

  return (
    <button onClick={() => setCount(count + 1)}>
      Clicked {count} times
    </button>
  );
}
```

You attach events using JSX attributes like `onClick`, `onChange`:

```jsx
function Button() {
  function handleClick() {
    alert('You clicked me!');
  }

  return <button onClick={handleClick}>Click me</button>;
}
```
Note: pass the function itself — don't call it with `()`!

You can show different UI based on conditions using regular JavaScript:

```jsx
function Greeting({ isLoggedIn }) {
  if (isLoggedIn) {
    return <h1>Welcome back!</h1>;
  }
  return <h1>Please log in.</h1>;
}
```

Or use the `&&` shorthand: `{isLoggedIn && <UserPanel />}`

Use `.map()` to render a list of items:

```jsx
const fruits = ['Apple', 'Banana', 'Cherry'];

function FruitList() {
  return (
    <ul>
      {fruits.map(fruit => (
        <li key={fruit}>{fruit}</li>
      ))}
    </ul>
  );
}
```

Always add a `key` prop — React needs it to track items!

`useEffect` lets you run code after the component renders — like fetching data:

```jsx
import { useState, useEffect } from 'react';

function User({ id }) {
  const [user, setUser] = useState(null);

  useEffect(() => {
    fetch(`/api/users/${id}`)
      .then(r => r.json())
      .then(setUser);
  }, [id]); // runs when id changes

  return <div>{user?.name}</div>;
}

